+
+  it("calls onRunTest when run button is clicked", async () => {
+    const user = userEvent.setup();
+    const onRunTest = vi.fn();
+    const test = createMockTestQueueItem({
+      id: "test-run",
+      test: {
+        id: "ET-run",
